import "../quiz_question.dart";

const _subject = "French";

QuizQuestion _q(String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

/// JAMB French — 100 questions covering Written Comprehension, Grammar
/// and Structure (form classes, pronouns, verb conjugation, sentence
/// transformations, agreement rules), Phonetics, and Culture/Civilization
/// of France and Francophone West Africa.
List<QuizQuestion> buildJambFrenchQuestions() {
  return [
    ..._writtenComprehension,
    ..._grammarFormsAndPronouns,
    ..._verbsAndConjugation,
    ..._sentenceTransformations,
    ..._numberAndGenderAgreement,
    ..._phonetics,
    ..._cultureAndCivilization,
  ];
}

const _passage =
    "Depuis quelques annees, de plus en plus de jeunes Africains quittent leurs villages pour s'installer dans "
    "les grandes villes. Ils esperent y trouver du travail et une vie meilleure. Malheureusement, beaucoup "
    "d'entre eux ne trouvent pas d'emploi facilement, et certains doivent vivre dans des conditions tres "
    "difficiles. Malgre ces difficultes, la population urbaine continue d'augmenter chaque annee. Les "
    "gouvernements essaient de creer plus d'emplois et de meilleures infrastructures pour repondre a ce "
    "probleme croissant.";

QuizQuestion _cq(String question, List<String> options, String correct, String explanation) {
  return _q("$_passage\n\n$question", options, correct, explanation);
}

